// Los datos POST están en $json.body
const body = $json.body || {};
const { nombre, email, servicio, fecha, hora, personas } = body;

const errors = [];

// Validar campos obligatorios
if (!nombre || nombre.trim().length < 2) errors.push('nombre es requerido (mínimo 2 caracteres)');
if (!email) errors.push('email es requerido');

// Validar formato de email sin regex con $
if (email) {
  const parts = email.split('@');
  const isValidEmail = parts.length === 2 && parts[0].length > 0 && parts[1].includes('.') && parts[1].split('.').pop().length >= 2;
  if (!isValidEmail) errors.push('formato de email no válido');
}

if (!servicio || !['spa', 'restaurante'].includes(servicio.toLowerCase())) {
  errors.push('servicio debe ser spa o restaurante');
}
if (!fecha || fecha.length !== 10 || fecha[4] !== '-' || fecha[7] !== '-') {
  errors.push('fecha debe tener formato YYYY-MM-DD');
}
if (!hora || hora.length !== 5 || hora[2] !== ':') {
  errors.push('hora debe tener formato HH:MM');
}

const pax = parseInt(personas, 10);
if (!personas || isNaN(pax) || pax < 1) {
  errors.push('personas debe ser un número mayor a 0');
}

if (errors.length > 0) {
  return [{ json: { ok: false, error: errors.join('. '), valid: false } }];
}

// Devolver datos limpios y normalizados
return [{ json: {
  nombre: nombre.trim(),
  email: email.toLowerCase().trim(),
  servicio: servicio.toLowerCase(),
  fecha,
  hora,
  personas: pax,
  valid: true
} }];

// Reservas actuales para este slot
const reservas = $input.all();

// Datos de la nueva reserva
const data = $('Validar Reserva').first().json;

// Aforo máximo según servicio
const aforo_max = data.servicio === 'spa' ? 4 : 20;

// Calcular personas ya reservadas en este slot
const ocupado = reservas.reduce((sum, r) => {
  return sum + (parseInt(r.json.personas, 10) || 1);
}, 0);

// ¿Caben las nuevas personas?
const disponible = (ocupado + data.personas) <= aforo_max;

return [{ json: { ...data, ocupado, aforo_max, disponible } }];
